<# .SYNOPSIS Verifies Personal and Enterprise remain separate overlays over one core. #>
param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path(Join-Path $PSScriptRoot '..\..')).Path;$layout=Get-Content -LiteralPath (Join-Path $root 'repository-layout.json') -Raw -Encoding UTF8|ConvertFrom-Json;$personal=Join-Path $root $layout.editions.personal;$enterprise=Join-Path $root $layout.editions.enterprise;$cases=@([pscustomobject]@{name='two_explicit_editions';passed=((Test-Path(Join-Path $personal 'edition.yaml'))-and(Test-Path(Join-Path $enterprise 'edition.yaml')))},[pscustomobject]@{name='edition_manifests_are_distinct';passed=((Get-Content(Join-Path $personal 'edition.yaml')-Raw)-ne(Get-Content(Join-Path $enterprise 'edition.yaml')-Raw))},[pscustomobject]@{name='single_shared_core';passed=((Test-Path(Join-Path $root '.qianlima'))-and-not(Test-Path(Join-Path $personal '.qianlima'))-and-not(Test-Path(Join-Path $enterprise '.qianlima')))},[pscustomobject]@{name='separate_docs_configs_and_tests';passed=((Test-Path(Join-Path $personal 'README.md'))-and(Test-Path(Join-Path $enterprise 'README.md'))-and(Test-Path(Join-Path $personal 'config.example.yaml'))-and(Test-Path(Join-Path $enterprise 'config.example.yaml'))-and(Test-Path(Join-Path $personal 'test-personal-profile.ps1'))-and(Test-Path(Join-Path $enterprise 'test-enterprise-profile.ps1')))});$failed=@($cases|?{-not$_.passed});$r=[pscustomobject]@{passed=($failed.Count-eq0);shared_core='.qianlima';personal='editions/personal';enterprise='editions/enterprise';cases=$cases};if($PassThru){$r|ConvertTo-Json -Depth 8}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Edition separation failed: '+(($failed.name)-join', '))}
